function shuffle(a){const b=[...a];for(let i=b.length-1;i>0;i--){const j=Math.floor(Math.random()*(i+1));[b[i],b[j]]=[b[j],b[i]];}return b;}

/* ═══ SOUNDS ═══ */
let soundOn=true;
function ps(f,d,v){if(!soundOn)return;try{const c=new(window.AudioContext||window.webkitAudioContext)();const o=c.createOscillator();const g=c.createGain();o.type="sine";o.frequency.value=f;g.gain.setValueAtTime(v||.12,c.currentTime);g.gain.exponentialRampToValueAtTime(.001,c.currentTime+d);o.connect(g);g.connect(c.destination);o.start();o.stop(c.currentTime+d);}catch(e){}}
function sClick(){ps(800,.12);}function sCorrect(){ps(600,.1);setTimeout(()=>ps(900,.15),100);}function sWrong(){ps(350,.3,.1);}function sStreak(){ps(500,.08);setTimeout(()=>ps(700,.08),80);setTimeout(()=>ps(1000,.12),160);}function sDone(){[440,554,659,880].forEach((f,i)=>setTimeout(()=>ps(f,.2),i*120));}

/* ═══ SPEECH ═══ */
let dutchVoice = null;
let voicesLoaded = false;
function loadVoices() {
  const voices = speechSynthesis.getVoices();
  if (voices.length > 0) {
    dutchVoice = voices.find(v => v.lang === 'nl-NL')
      || voices.find(v => v.lang.startsWith('nl'))
      || voices.find(v => v.lang === 'nl-BE')
      || null;
    voicesLoaded = true;
  }
}
if (typeof speechSynthesis !== 'undefined') {
  loadVoices();
  speechSynthesis.onvoiceschanged = loadVoices;
}
function speakNL(word) {
  try {
    if (!voicesLoaded) loadVoices();
    speechSynthesis.cancel();
    const u = new SpeechSynthesisUtterance(word);
    u.lang = 'nl-NL';
    if (dutchVoice) u.voice = dutchVoice;
    u.rate = 0.85;
    u.pitch = 1.0;
    speechSynthesis.speak(u);
  } catch(e) {}
}

/* ═══ STORAGE ═══ */
async function sGet(k){try{const r=localStorage.getItem("dl_"+k);return v?JSON.parse(v):null;}catch(e){return null;}}
async function sSet(k,v){try{localStorage.setItem("dl_"+k,JSON.stringify(v));}catch(e){}}
async function sGetShared(k){try{const r=localStorage.getItem("dl_shared_"+k);return v?JSON.parse(v):null;}catch(e){return null;}}
async function sSetShared(k,v){try{localStorage.setItem("dl_shared_"+k,JSON.stringify(v));}catch(e){}}

/* ═══ EXERCISE GENERATION ═══ */
function genEx(words,lang,weakWords,includeListen,includeEmoji){
  let pool=[...words];
  if(weakWords&&weakWords.length>0){const ws=new Set(weakWords);const weak=pool.filter(w=>ws.has(w.d));const strong=pool.filter(w=>!ws.has(w.d));pool=[...shuffle(weak).slice(0,8),...shuffle(strong).slice(0,6)];}
  const ws=shuffle(pool).slice(0,12);const ex=[];
  const tr=w=>lang==="en"?w.en:w.fa;
  // Multiple choice
  ws.slice(0,6).forEach(w=>{const oth=shuffle(words.filter(x=>x.d!==w.d)).slice(0,3).map(x=>tr(x));ex.push({type:"mc",dw:w.d,ca:tr(w),opts:shuffle([tr(w),...oth]),hint:w.d+" = "+tr(w)});});
  // Type word
  ws.slice(0,4).forEach(w=>{ex.push({type:"tw",tr:tr(w),ca:w.d,hint:'"'+w.d[0]+'..."'});});
  // Listening exercise
  if(includeListen!==false){ws.slice(0,3).forEach(w=>{const oth=shuffle(words.filter(x=>x.d!==w.d)).slice(0,3).map(x=>x.d);ex.push({type:"listen",word:w.d,ca:w.d,opts:shuffle([w.d,...oth]),hint:tr(w)});});}
  // Emoji exercise
  if(includeEmoji!==false){const emojiWords=ws.filter(w=>EMOJI[w.d]);shuffle(emojiWords).slice(0,3).forEach(w=>{const oth=shuffle(words.filter(x=>x.d!==w.d&&EMOJI[x.d])).slice(0,3).map(x=>x.d);if(oth.length>=3)ex.push({type:"emoji",emoji:EMOJI[w.d],ca:w.d,opts:shuffle([w.d,...oth]),hint:tr(w)});});}
  // Drag match
  const sw=shuffle(ws);for(let i=0;i<sw.length;i+=3){const b=sw.slice(i,i+3);if(b.length>=2)ex.push({type:"dm",pairs:b.map(w=>({d:w.d,t:tr(w)}))});}
  return shuffle(ex);
}
function genSentenceEx(sentences){if(!sentences||!sentences.length)return[];return shuffle(sentences).slice(0,3).map(s=>({type:"fb",sentence:s.s,answer:s.a,hint:s.h}));}

/* ═══ SVG CAT ═══ */
const catC=["#FFB347","#9E9E9E","#424242","#F5F5F5","#FFCC80","#FF8A65","#78909C","#D7CCC8","#FFA726","#A1887F","#37474F","#FFE0B2"];
const catBg=["#FFF8E1","#F3E5F5","#E8EAF6","#E0F7FA","#FFF3E0","#FCE4EC","#E8F5E9","#E3F2FD","#F1F8E9","#FCE4EC","#ECEFF1","#EDE7F6"];
function MiniCat({v=0,w=80,h=80}){const fur=catC[v%12],bg=catBg[v%12],cx=w/2,cy=h/2+4;return(<svg width={w} height={h} viewBox={"0 0 "+w+" "+h} style={{borderRadius:12,display:"block"}}><rect width={w} height={h} fill={bg} rx="12"/><ellipse cx={cx} cy={cy+12} rx={w*.22} ry={h*.18} fill={fur}/><ellipse cx={cx} cy={cy-4} rx={w*.2} ry={h*.18} fill={fur}/><polygon points={(cx-15)+","+(cy-12)+" "+(cx-20)+","+(cy-30)+" "+(cx-8)+","+(cy-14)} fill={fur}/><polygon points={(cx+15)+","+(cy-12)+" "+(cx+20)+","+(cy-30)+" "+(cx+8)+","+(cy-14)} fill={fur}/><polygon points={(cx-13)+","+(cy-13)+" "+(cx-17)+","+(cy-26)+" "+(cx-9)+","+(cy-14)} fill="#FFADB5"/><polygon points={(cx+13)+","+(cy-13)+" "+(cx+17)+","+(cy-26)+" "+(cx+9)+","+(cy-14)} fill="#FFADB5"/><ellipse cx={cx-6} cy={cy-5} rx="4.5" ry="4.5" fill="white"/><ellipse cx={cx+6} cy={cy-5} rx="4.5" ry="4.5" fill="white"/><circle cx={cx-5} cy={cy-4} r="3" fill="#2D2D2D"/><circle cx={cx+5} cy={cy-4} r="3" fill="#2D2D2D"/><circle cx={cx-4} cy={cy-6} r="1.2" fill="white"/><circle cx={cx+4} cy={cy-6} r="1.2" fill="white"/><ellipse cx={cx} cy={cy+1} rx="2" ry="1.5" fill="#FF8A80"/><path d={"M"+(cx-4)+" "+(cy+3)+" Q"+(cx-2)+" "+(cy+6)+" "+cx+" "+(cy+3)} fill="none" stroke="#BF6B50" strokeWidth="1.2" strokeLinecap="round"/><path d={"M"+cx+" "+(cy+3)+" Q"+(cx+2)+" "+(cy+6)+" "+(cx+4)+" "+(cy+3)} fill="none" stroke="#BF6B50" strokeWidth="1.2" strokeLinecap="round"/><ellipse cx={cx-12} cy={cy+1} rx="3.5" ry="2.5" fill="#FFADB5" opacity=".3"/><ellipse cx={cx+12} cy={cy+1} rx="3.5" ry="2.5" fill="#FFADB5" opacity=".3"/></svg>);}

const PawIcon=({filled})=>(<svg width="20" height="20" viewBox="0 0 24 24" fill={filled?"#FF6B9D":"var(--c-muted,#ddd)"}><ellipse cx="12" cy="17" rx="5" ry="4"/><circle cx="7" cy="11" r="2.5"/><circle cx="17" cy="11" r="2.5"/><circle cx="5" cy="14.5" r="2"/><circle cx="19" cy="14.5" r="2"/></svg>);
const ProgressBar=({current,total})=>(<div style={{width:"100%",height:12,background:"var(--c-border,#e8e8e8)",borderRadius:99,overflow:"hidden"}}><div style={{height:"100%",width:(current/total*100)+"%",background:"linear-gradient(90deg,#58CC02,#7BDB2E)",borderRadius:99,transition:"width .5s"}}/></div>);
const SpeakerBtn=({word,big})=>(<button onClick={e=>{e.stopPropagation();speakNL(word);}} style={{background:"none",border:"none",cursor:"pointer",fontSize:big?28:18,padding:big?"4px 8px":"6px 8px",minWidth:36,minHeight:36,opacity:.7,touchAction:"manipulation"}} title="Listen">🔊</button>);

const hCap=["Meow-velous!","Purrfect!","Feline fine!","Pawsome!","Cat-astic!","Claw-some!","Purr-ecisely!"];
const sCap=["Oopsie meow!","Try again!","Almost!","Don't give up!","Next time!","Keep going!","9 lives!"];
let gci=0,gcc2=0;
function CatReward({ok,big}){const[v]=useState(()=>{const i=gci;gci=(gci+1)%12;return i;});const[ci]=useState(()=>{const i=gcc2;gcc2++;return i;});const caps=ok?hCap:sCap;const sz=big?120:90;const bc=ok?"#58CC02":"#FF6B9D";return(<div style={{textAlign:"center",margin:"6px 0",animation:"bounceIn .4s ease-out"}}><div style={{display:"inline-block",borderRadius:12,overflow:"hidden",border:"3px solid "+bc}}><MiniCat v={v} w={sz} h={sz}/></div><p style={{fontSize:11,fontWeight:700,color:bc,marginTop:3,fontStyle:"italic"}}>{caps[ci%caps.length]}</p></div>);}

function HintBtn({hint,label,onUse}){const[show,setShow]=useState(false);if(show)return(<div style={{marginTop:10,background:"var(--c-hint-bg,#FFFDE7)",border:"2px solid #FFD54F",borderRadius:10,padding:"8px 14px",textAlign:"center",animation:"bounceIn .3s ease-out"}}><p style={{fontSize:10,fontWeight:800,color:"#F57F17",marginBottom:1}}>{"💡 "+label}</p><p style={{fontSize:13,fontWeight:600,color:"var(--c-text,#5D4037)"}}>{hint}</p></div>);return(<div style={{marginTop:10,textAlign:"center"}}><button onClick={()=>{setShow(true);if(onUse)onUse();}} style={{background:"linear-gradient(135deg,#FFF3CD,#FFECB3)",border:"2px solid #FFD54F",borderRadius:10,padding:"6px 16px",cursor:"pointer",fontSize:12,fontWeight:700,color:"#F57F17"}}>{"💡 "+label+" (-5 XP)"}</button></div>);}

function DragMatch({pairs,isRTL,ui,onDone}){const[dI]=useState(()=>shuffle(pairs.map(p=>p.d)));const[tI]=useState(()=>shuffle(pairs.map(p=>p.t)));const[m,setM]=useState({});const[sel,setSel]=useState(null);const[res,setRes]=useState(null);
  const doCheck=()=>{const r={};let ok=true;Object.entries(m).forEach(([d,t])=>{const p=pairs.find(p=>p.d===d);const c=p&&p.t===t;r[d]=c;if(!c)ok=false;});setRes(r);const cc=Object.values(r).filter(Boolean).length;setTimeout(()=>onDone(ok,cc,pairs.length),700);};
  const done=Object.keys(m).length===pairs.length;const mT=Object.values(m);
  return(<div><p style={{fontSize:13,fontWeight:700,color:"var(--c-sub)",marginBottom:10,textAlign:"center"}}>{ui.match}</p>
    <div style={{display:"flex",gap:10,justifyContent:"center",flexWrap:"wrap"}}>
      <div style={{display:"flex",flexDirection:"column",gap:6,flex:1,minWidth:90,maxWidth:170}}>
        <div style={{fontSize:9,fontWeight:800,color:"#1CB0F6",textTransform:"uppercase",textAlign:"center"}}>Nederlands</div>
        {dI.map(w=>{const isSel=sel===w,isM=w in m,isOk=res&&res[w]===true,isBad=res&&res[w]===false;let bg="var(--c-card)",bc="var(--c-border)",c="var(--c-text)";if(isOk){bg="#E8F9E0";bc="#58CC02";c="#2E7D00";}else if(isBad){bg="#FFE8E8";bc="#FF4B4B";c="#C00";}else if(isSel){bg="#E3F2FD";bc="#1CB0F6";c="#0077CC";}else if(isM){bg="var(--c-muted-bg)";bc="var(--c-border)";c="var(--c-sub)";}return(<button key={w} onClick={()=>!res&&setSel(sel===w?null:w)} disabled={!!res} style={{padding:"12px 10px",minHeight:44,background:bg,border:"2px solid "+bc,borderRadius:10,fontSize:13,fontWeight:700,color:c,cursor:res?"default":"pointer",fontFamily:"'Nunito',sans-serif",transform:isSel?"scale(1.04)":"",transition:"all .15s"}}>{w}<SpeakerBtn word={w}/></button>);})}
      </div>
      <div style={{display:"flex",flexDirection:"column",gap:6,flex:1,minWidth:90,maxWidth:170}}>
        <div style={{fontSize:9,fontWeight:800,color:"#CE82FF",textTransform:"uppercase",textAlign:"center"}}>{isRTL?"ترجمه":"Translation"}</div>
        {tI.map(w=>{const isM=mT.includes(w),canTap=sel&&!isM&&!res;const dK=Object.entries(m).find(([,v])=>v===w);const dKey=dK?dK[0]:null;let bg="var(--c-card)",bc="var(--c-border)",c="var(--c-text)";if(dKey&&res&&res[dKey]===true){bg="#E8F9E0";bc="#58CC02";c="#2E7D00";}else if(dKey&&res&&res[dKey]===false){bg="#FFE8E8";bc="#FF4B4B";c="#C00";}else if(canTap){bg="#FFF3E0";bc="#FFB347";c="#E65100";}else if(isM){bg="var(--c-muted-bg)";bc="var(--c-border)";c="var(--c-sub)";}return(<button key={w} onClick={()=>{if(canTap){setM(x=>({...x,[sel]:w}));setSel(null);}}} disabled={!canTap} style={{padding:"12px 10px",minHeight:44,background:bg,border:"2px solid "+bc,borderRadius:10,fontSize:13,fontWeight:700,color:c,cursor:canTap?"pointer":"default",fontFamily:"'Nunito',sans-serif",direction:isRTL?"rtl":"ltr"}}>{w}</button>);})}
      </div>
    </div>
    {Object.keys(m).length>0&&!res&&<div style={{marginTop:8}}>{Object.entries(m).map(([d,t])=>(<div key={d} style={{display:"flex",alignItems:"center",justifyContent:"center",gap:5,padding:"4px 10px",background:"var(--c-muted-bg)",borderRadius:8,marginBottom:3,fontSize:12,fontWeight:600,color:"var(--c-sub)",border:"1px solid var(--c-border)"}}>{d} ↔ {t}<button onClick={()=>setM(x=>{const n={...x};delete n[d];return n;})} style={{background:"none",border:"none",cursor:"pointer",fontSize:12,color:"var(--c-border)"}}>✕</button></div>))}</div>}
    {!res&&<button onClick={doCheck} disabled={!done} style={{width:"100%",padding:"12px",border:"none",borderRadius:12,marginTop:8,fontSize:14,fontWeight:800,cursor:done?"pointer":"default",background:done?"linear-gradient(135deg,#58CC02,#46A302)":"var(--c-muted-bg)",color:done?"white":"var(--c-sub)",textTransform:"uppercase",fontFamily:"'Nunito'"}}>{ui.check}</button>}
    {res&&<div style={{marginTop:8}}>{Object.entries(res).map(([d,ok])=>{const p=pairs.find(p=>p.d===d);return(<div key={d} style={{display:"flex",alignItems:"center",justifyContent:"center",gap:5,padding:"5px 10px",borderRadius:8,marginBottom:3,background:ok?"#E8F9E0":"#FFE8E8",border:"2px solid "+(ok?"#58CC02":"#FF4B4B"),fontSize:12,fontWeight:700,color:ok?"#2E7D00":"#C00"}}>{ok?"✓":"✗"} {d} → {m[d]} {!ok&&<span style={{color:"#888",fontSize:10}}>(→{p.t})</span>}</div>);})}</div>}
  </div>);
}

/* ═══ FLASHCARDS ═══ */
function FlashcardGame({words, lang, onBack, ui}) {
  const [deck, setDeck] = useState([]);
  const [curIdx, setCurIdx] = useState(0);
  const [flipped, setFlipped] = useState(false);
  const [dir, setDir] = useState("nl"); // "nl" = show Dutch first, "tr" = show translation first
  const [known, setKnown] = useState([]);
  const [unknown, setUnknown] = useState([]);
  const [phase, setPhase] = useState("setup"); // setup, playing, done

  const startDeck = (direction) => {
    setDir(direction);
    setDeck(shuffle([...words]));
    setCurIdx(0);
    setFlipped(false);
    setKnown([]);
    setUnknown([]);
    setPhase("playing");
  };

  const markCard = (isKnown) => {
    const w = deck[curIdx];
    if (isKnown) { setKnown(k => [...k, w]); sCorrect(); }
    else { setUnknown(u => [...u, w]); sWrong(); }
    if (curIdx + 1 >= deck.length) {
      setPhase("done");
    } else {
      setCurIdx(i => i + 1);
      setFlipped(false);
    }
  };

  const practiceUnknown = () => {
    if (unknown.length === 0) return;
    setDeck(shuffle([...unknown]));
    setCurIdx(0);
    setFlipped(false);
    setKnown([]);
    setUnknown([]);
    setPhase("playing");
  };

  const tr = (w) => lang === "en" ? w.en : w.fa;
  const card = deck[curIdx];
  const frontText = card ? (dir === "nl" ? card.d : tr(card)) : "";
  const backText = card ? (dir === "nl" ? tr(card) : card.d) : "";
  const dutchWord = card ? card.d : "";
  const pct = deck.length > 0 ? Math.round(((curIdx) / deck.length) * 100) : 0;

  // Setup screen - choose direction
  if (phase === "setup") return (
    <div style={{textAlign:"center",padding:"20px 0"}}>
      <div style={{marginBottom:20}}>
        <MiniCat v={3} w={80} h={80} />
      </div>
      <h3 style={{fontSize:20,fontWeight:900,color:"var(--c-text)",marginBottom:4}}>{ui.fcTitle}</h3>
      <p style={{fontSize:13,color:"var(--c-sub)",marginBottom:20}}>{words.length + " " + ui.wordCount}</p>

      <button onClick={() => startDeck("nl")} style={{
        width:"100%",padding:"16px",background:"linear-gradient(135deg,#1CB0F6,#0095E8)",
        border:"none",borderRadius:14,color:"white",fontSize:15,fontWeight:800,
        cursor:"pointer",marginBottom:10,minHeight:52,fontFamily:"'Nunito'"
      }}>
        {"🇳🇱 → " + (lang === "fa" ? "🇮🇷" : "🇬🇧")}
        <br/><span style={{fontSize:12,fontWeight:600,opacity:.8}}>{ui.fcNlToTr}</span>
      </button>

      <button onClick={() => startDeck("tr")} style={{
        width:"100%",padding:"16px",background:"linear-gradient(135deg,#CE82FF,#A855F7)",
        border:"none",borderRadius:14,color:"white",fontSize:15,fontWeight:800,
        cursor:"pointer",marginBottom:16,minHeight:52,fontFamily:"'Nunito'"
      }}>
        {(lang === "fa" ? "🇮🇷" : "🇬🇧") + " → 🇳🇱"}
        <br/><span style={{fontSize:12,fontWeight:600,opacity:.8}}>{ui.fcTrToNl}</span>
      </button>

      <button onClick={onBack} style={{
        background:"none",border:"2px solid var(--c-border)",borderRadius:12,
        padding:"10px 20px",cursor:"pointer",fontSize:13,fontWeight:700,color:"var(--c-sub)"
      }}>{"← " + ui.back}</button>
    </div>
  );

  // Done screen
  if (phase === "done") {
    const total = known.length + unknown.length;
    const pctDone = Math.round((known.length / total) * 100);
    return (
      <div style={{textAlign:"center",padding:"20px 0"}}>
        <CatReward ok={pctDone >= 70} big />
        <h3 style={{fontSize:22,fontWeight:900,color:"var(--c-text)",marginBottom:8}}>{ui.fcDone}</h3>

        <div style={{display:"flex",justifyContent:"center",gap:16,marginBottom:20}}>
          <div style={{textAlign:"center"}}>
            <div style={{width:56,height:56,borderRadius:"50%",background:"#58CC02",display:"flex",alignItems:"center",justifyContent:"center",margin:"0 auto 6px"}}>
              <span style={{fontSize:20,fontWeight:900,color:"white"}}>{known.length}</span>
            </div>
            <span style={{fontSize:11,fontWeight:700,color:"#58CC02"}}>{ui.fcKnown}</span>
          </div>
          <div style={{textAlign:"center"}}>
            <div style={{width:56,height:56,borderRadius:"50%",background:"#FF6B9D",display:"flex",alignItems:"center",justifyContent:"center",margin:"0 auto 6px"}}>
              <span style={{fontSize:20,fontWeight:900,color:"white"}}>{unknown.length}</span>
            </div>
            <span style={{fontSize:11,fontWeight:700,color:"#FF6B9D"}}>{ui.fcUnknown}</span>
          </div>
        </div>

        {unknown.length > 0 && (
          <button onClick={practiceUnknown} style={{
            width:"100%",padding:"14px",background:"linear-gradient(135deg,#FF6B35,#E65100)",
            border:"none",borderRadius:14,color:"white",fontSize:15,fontWeight:800,
            cursor:"pointer",marginBottom:10,minHeight:48,fontFamily:"'Nunito'"
          }}>{"🔄 " + ui.fcRetry + " (" + unknown.length + ")"}</button>
        )}

        <button onClick={() => setPhase("setup")} style={{
          width:"100%",padding:"14px",background:"linear-gradient(135deg,#1CB0F6,#0095E8)",
          border:"none",borderRadius:14,color:"white",fontSize:15,fontWeight:800,
          cursor:"pointer",marginBottom:10,minHeight:48,fontFamily:"'Nunito'"
        }}>{"🔀 " + ui.fcRestart}</button>

        <button onClick={onBack} style={{
          width:"100%",padding:"12px",background:"transparent",border:"2px solid var(--c-border)",
          borderRadius:14,color:"var(--c-sub)",fontSize:13,fontWeight:700,cursor:"pointer"
        }}>{"← " + ui.back}</button>
      </div>
    );
  }

  // Playing screen
  return (
    <div style={{padding:"10px 0"}}>
      {/* Progress */}
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:12}}>
        <button onClick={onBack} style={{background:"none",border:"none",cursor:"pointer",fontSize:18,color:"var(--c-sub)",padding:8,minWidth:40,minHeight:40}}>✕</button>
        <span style={{fontSize:13,fontWeight:800,color:"var(--c-sub)"}}>{(curIdx + 1) + " / " + deck.length}</span>
        <span style={{fontSize:13,fontWeight:700,color:"#58CC02"}}>{"✓ " + known.length}</span>
      </div>
      <ProgressBar current={curIdx} total={deck.length} />

      {/* Card */}
      <div
        onClick={() => { if (!flipped) { setFlipped(true); speakNL(dutchWord); } }}
        style={{
          background: "var(--c-card)",
          borderRadius: 20,
          padding: "40px 24px",
          marginTop: 20,
          marginBottom: 20,
          minHeight: 220,
          display: "flex",
          flexDirection: "column",
          alignItems: "center",
          justifyContent: "center",
          cursor: flipped ? "default" : "pointer",
          border: "3px solid " + (flipped ? "#58CC02" : "var(--c-border)"),
          boxShadow: "0 6px 24px rgba(0,0,0,.08)",
          transition: "all .3s ease",
          animation: "bounceIn .4s ease-out",
        }}
      >
        {/* Front */}
        <div style={{fontSize:12,fontWeight:700,color:"var(--c-sub)",textTransform:"uppercase",marginBottom:12}}>
          {dir === "nl" ? "🇳🇱 Nederlands" : (lang === "fa" ? "🇮🇷 فارسی" : "🇬🇧 English")}
        </div>
        <div style={{fontSize:28,fontWeight:900,color:"var(--c-text)",marginBottom:8,textAlign:"center"}}>
          {frontText}
        </div>
        {dir === "nl" && !flipped && <SpeakerBtn word={dutchWord} big />}
        {EMOJI[dutchWord] && <span style={{fontSize:32,marginTop:4}}>{EMOJI[dutchWord]}</span>}

        {!flipped && (
          <p style={{fontSize:13,color:"var(--c-sub)",marginTop:16,fontWeight:600}}>
            {ui.fcTap}
          </p>
        )}

        {/* Back (answer) */}
        {flipped && (
          <div style={{marginTop:16,paddingTop:16,borderTop:"2px dashed var(--c-border)",width:"100%",textAlign:"center",animation:"fadeUp .3s ease-out"}}>
            <div style={{fontSize:12,fontWeight:700,color:"var(--c-sub)",textTransform:"uppercase",marginBottom:8}}>
              {dir === "nl" ? (lang === "fa" ? "🇮🇷 فارسی" : "🇬🇧 English") : "🇳🇱 Nederlands"}
            </div>
            <div style={{fontSize:26,fontWeight:900,color:dir === "nl" ? "#CE82FF" : "#1CB0F6",marginBottom:8}}>
              {backText}
            </div>
            {dir === "tr" && <SpeakerBtn word={dutchWord} big />}
            {dir === "nl" && <SpeakerBtn word={dutchWord} />}
          </div>
        )}
      </div>

      {/* Action buttons */}
      {flipped && (
        <div style={{display:"flex",gap:10,animation:"fadeUp .3s ease-out"}}>
          <button onClick={() => markCard(false)} style={{
            flex:1,padding:"16px",background:"linear-gradient(135deg,#FFE8E8,#FFD4D4)",
            border:"3px solid #FF6B9D",borderRadius:14,fontSize:15,fontWeight:800,
            color:"#C00",cursor:"pointer",minHeight:56,fontFamily:"'Nunito'",
            display:"flex",flexDirection:"column",alignItems:"center",gap:2,
          }}>
            <span style={{fontSize:22}}>🙀</span>
            {ui.fcDontKnow}
          </button>
          <button onClick={() => markCard(true)} style={{
            flex:1,padding:"16px",background:"linear-gradient(135deg,#E8F9E0,#D4F4C4)",
            border:"3px solid #58CC02",borderRadius:14,fontSize:15,fontWeight:800,
            color:"#2E7D00",cursor:"pointer",minHeight:56,fontFamily:"'Nunito'",
            display:"flex",flexDirection:"column",alignItems:"center",gap:2,
          }}>
            <span style={{fontSize:22}}>😻</span>
            {ui.fcKnow}
          </button>
        </div>
      )}

      {!flipped && (
        <p style={{textAlign:"center",fontSize:12,color:"var(--c-sub)",marginTop:8}}>
          {ui.fcTapCard}
        </p>
      )}
    </div>
  );
}

/* ═══ TIMER ═══ */
function Timer({seconds,onDone}){const[left,setLeft]=useState(seconds);useEffect(()=>{if(left<=0){onDone();return;}const t=setTimeout(()=>setLeft(l=>l-1),1000);return()=>clearTimeout(t);},[left]);const m=Math.floor(left/60);const s=left%60;const pct=left/seconds*100;const urgent=left<30;return(<div style={{textAlign:"center",marginBottom:10}}><div style={{width:"100%",height:8,background:"var(--c-border)",borderRadius:99,overflow:"hidden",marginBottom:4}}><div style={{height:"100%",width:pct+"%",background:urgent?"#FF4B4B":"#1CB0F6",borderRadius:99,transition:"width 1s linear"}}/></div><span style={{fontSize:16,fontWeight:900,color:urgent?"#FF4B4B":"var(--c-text)",fontFamily:"'Nunito'"}}>{m}:{s<10?"0"+s:s}</span></div>);}

/* ═══ BADGES ═══ */
const BADGES=[{id:"first",name:"First Steps",icon:"🐱",check:p=>p.lc>=1},{id:"five",name:"Curious Cat",icon:"😺",check:p=>p.lc>=5},{id:"ten",name:"Studious Kitty",icon:"😹",check:p=>p.lc>=10},{id:"perfect",name:"Purrfect Score",icon:"🏆",check:p=>p.ps>=1},{id:"streak3",name:"On Fire",icon:"🔥",check:p=>p.sk>=3},{id:"streak7",name:"Dedicated",icon:"⭐",check:p=>p.sk>=7},{id:"allch",name:"Graduate Cat",icon:"🎓",check:p=>p.cs>=10},{id:"words100",name:"Vocab Pro",icon:"📚",check:p=>p.wl>=100},{id:"review",name:"Review Master",icon:"🔄",check:p=>p.rd>=1},{id:"poly",name:"Polyglot",icon:"🌍",check:p=>p.lu>=2},{id:"exam",name:"Exam Ace",icon:"📝",check:p=>p.ex>=1}];

/* ═══ CSS ═══ */
const CSS=`@import url('https://fonts.googleapis.com/css2?family=Nunito:wght@400;600;700;800;900&display=swap');
:root{--c-bg:#FFF8F0;--c-bg2:#FFF0E6;--c-bg3:#FFEADD;--c-card:white;--c-text:#1a1a2e;--c-sub:#888;--c-border:#f0f0f0;--c-muted:#ddd;--c-muted-bg:#F5F5F5;--c-hint-bg:#FFFDE7;}
[data-theme="dark"]{--c-bg:#1a1a2e;--c-bg2:#16213e;--c-bg3:#0f3460;--c-card:#1e2746;--c-text:#e0e0e0;--c-sub:#8899aa;--c-border:#2a3a5e;--c-muted:#445;--c-muted-bg:#253050;--c-hint-bg:#2a2a1e;}
@keyframes float{0%,100%{transform:translateY(0)}50%{transform:translateY(-8px)}}
@keyframes fadeUp{from{opacity:0;transform:translateY(16px)}to{opacity:1;transform:translateY(0)}}
@keyframes shake{0%,100%{transform:translateX(0)}25%{transform:translateX(-6px)}75%{transform:translateX(6px)}}
@keyframes bounceIn{0%{transform:scale(.85);opacity:0}60%{transform:scale(1.03)}100%{transform:scale(1);opacity:1}}
@keyframes slideUp{from{transform:translateY(24px);opacity:0}to{transform:translateY(0);opacity:1}}
@keyframes pulse{0%,100%{transform:scale(1)}50%{transform:scale(1.04)}}
*{box-sizing:border-box;margin:0;padding:0;-webkit-tap-highlight-color:transparent;}
html{-webkit-text-size-adjust:100%;scroll-behavior:smooth;}
body{overscroll-behavior-y:contain;}
input{font-size:16px!important;}
button{-webkit-appearance:none;touch-action:manipulation;}
@media(max-width:400px){
  .card-inner{padding:16px 14px!important;}
}
`;

const UI={
  en:{choose:"Choose the correct translation",type:"Type the Dutch word",match:"Match Dutch to English",fill:"Fill in the blank",listen:"Listen and choose the word",emojiQ:"Which Dutch word matches this?",check:"Check",next:"Continue",correct:"Purrfect!",incorrect:"Not quite!",tryAgain:"Answer",score:"Score",streak:"Streak",complete:"Lesson Complete!",restart:"Again",startLesson:"Start Lesson",selectLang:"Language",meaning:"means",greatJob:"Great job!",perfect:"Purrfect!",keepGoing:"Keep going!",hearts:"Lives",xp:"XP",hint:"Hint",selectCh:"Choose a chapter",back:"Back",wordCount:"words",review:"Review weak words",achievements:"Badges",darkMode:"Theme",sound:"Sound",dailyStreak:"streak",days:"days",locked:"Keep learning!",exam:"Exam Mode",examDesc:"Timed test across chapters",examStart:"Start Exam",examTime:"minutes",examDone:"Exam Complete!",leaderboard:"Leaderboard",lbName:"Your name",lbSubmit:"Submit",lbEmpty:"No scores yet!",grammar:"Grammar Tip",grammarShow:"Show tip",fcTitle:"Flashcards",fcNlToTr:"See Dutch, guess the meaning",fcTrToNl:"See the meaning, guess Dutch",fcTap:"Tap to reveal",fcTapCard:"Tap the card to see the answer",fcKnow:"I know it!",fcDontKnow:"Still learning",fcKnown:"Known",fcUnknown:"To review",fcDone:"Round Complete!",fcRetry:"Practice again",fcRestart:"New round",flashcards:"Flashcards"},
  fa:{choose:"ترجمه صحیح را انتخاب کنید",type:"کلمه هلندی را تایپ کنید",match:"هلندی به فارسی وصل کنید",fill:"جای خالی را پر کنید",listen:"گوش کنید و کلمه را انتخاب کنید",emojiQ:"کدام کلمه هلندی مطابقت دارد؟",check:"بررسی",next:"ادامه",correct:"صحیح!",incorrect:"نادرست!",tryAgain:"جواب",score:"امتیاز",streak:"پیاپی",complete:"درس تمام شد!",restart:"دوباره",startLesson:"شروع درس",selectLang:"زبان",meaning:"یعنی",greatJob:"آفرین!",perfect:"کامل!",keepGoing:"ادامه دهید!",hearts:"جان",xp:"امتیاز",hint:"راهنمایی",selectCh:"انتخاب فصل",back:"برگشت",wordCount:"کلمه",review:"مرور",achievements:"دستاوردها",darkMode:"تم",sound:"صدا",dailyStreak:"تمرین",days:"روز",locked:"ادامه دهید!",exam:"آزمون",examDesc:"آزمون زمان‌دار",examStart:"شروع آزمون",examTime:"دقیقه",examDone:"آزمون تمام شد!",leaderboard:"جدول امتیازات",lbName:"نام شما",lbSubmit:"ثبت",lbEmpty:"هنوز امتیازی ثبت نشده!",grammar:"نکته دستوری",grammarShow:"نمایش نکته",fcTitle:"فلش‌کارت",fcNlToTr:"هلندی ببینید، معنی حدس بزنید",fcTrToNl:"معنی ببینید، هلندی حدس بزنید",fcTap:"لمس کنید",fcTapCard:"کارت را لمس کنید تا جواب ببینید",fcKnow:"بلدم!",fcDontKnow:"هنوز یاد نگرفتم",fcKnown:"بلد",fcUnknown:"مرور",fcDone:"دور تمام شد!",fcRetry:"تمرین دوباره",fcRestart:"دور جدید",flashcards:"فلش‌کارت"},


};
const LANGS=[{c:"en",f:"🇬🇧",n:"English"},{c:"fa",f:"🇮🇷",n:"فارسی"}];
const chColors=["#1CB0F6","#58CC02","#CE82FF","#FF6B35","#FFD600","#FF4B4B","#1CB0F6","#58CC02","#CE82FF","#FF6B35"];

export default function App(){
  const[lang,setLang]=useState(null);const[screen,setScreen]=useState("lang");const[chapter,setChapter]=useState(null);
  const[exercises,setExercises]=useState([]);const[cur,setCur]=useState(0);const[score,setScore]=useState(0);
  const[streak,setStreak]=useState(0);const[hearts,setHearts]=useState(5);const[sel,setSel]=useState(null);
  const[typed,setTyped]=useState("");const[fb,setFb]=useState(null);const[xp,setXp]=useState(0);
  const[shk,setShk]=useState(false);const[hUsed,setHUsed]=useState(false);const[dk,setDk]=useState(0);
  const[conf,setConf]=useState(false);const[dark,setDark]=useState(()=>window.matchMedia?.("(prefers-color-scheme:dark)").matches||false);
  const[snd,setSnd]=useState(true);const[progress,setProgress]=useState({});const[weakWords,setWeakWords]=useState([]);
  const[dailyStreak,setDailyStreak]=useState(0);const[badges,setBadges]=useState([]);
  const[isReview,setIsReview]=useState(false);const[isExam,setIsExam]=useState(false);const[examOver,setExamOver]=useState(false);
  const[examChapters,setExamChapters]=useState([]);const[showGrammar,setShowGrammar]=useState(false);
  const[lb,setLb]=useState([]);const[lbName,setLbName]=useState("");
  const iRef=useRef(null);
  const isRTL=lang==="fa"||lang==="ar";const ui=lang?UI[lang]:UI.en;const total=exercises.length;

  // Set viewport meta for mobile
  useEffect(()=>{
    let meta=document.querySelector('meta[name="viewport"]');
    if(!meta){meta=document.createElement('meta');meta.name='viewport';document.head.appendChild(meta);}
    meta.content='width=device-width,initial-scale=1,maximum-scale=1,user-scalable=no,viewport-fit=cover';
    // Prevent pull-to-refresh
    document.body.style.overscrollBehavior='none';
    return()=>{document.body.style.overscrollBehavior='';};
  },[]);

  useEffect(()=>{(async()=>{const p=await sGet("progress")||{lc:0,ps:0,cs:0,wl:0,rd:0,lu:0,ex:0,chS:{},ww:[],ul:[]};const s=await sGet("streak")||{c:0,ld:""};const b=await sGet("badges")||[];const today=new Date().toISOString().slice(0,10);let sc=s.c;if(s.ld){const diff=Math.floor((new Date(today)-new Date(s.ld))/864e5);if(diff>1)sc=0;}setProgress(p);setWeakWords(p.ww||[]);setDailyStreak(sc);setBadges(b);})();},[]);

  const saveP=useCallback(async(u)=>{const p={...progress,...u};if(u.ww)setWeakWords(u.ww);setProgress(p);await sSet("progress",p);const today=new Date().toISOString().slice(0,10);const s=await sGet("streak")||{c:0,ld:""};let nc=s.c;if(s.ld!==today)nc=(s.ld&&(new Date(today)-new Date(s.ld))/864e5<=1)?s.c+1:1;setDailyStreak(nc);await sSet("streak",{c:nc,ld:today});const nb=BADGES.filter(b=>b.check({...p,sk:nc})).map(b=>b.id);setBadges(nb);await sSet("badges",nb);},[progress]);

  useEffect(()=>{document.documentElement.setAttribute("data-theme",dark?"dark":"light");},[dark]);
  useEffect(()=>{soundOn=snd;},[snd]);

  // Load leaderboard
  const loadLb=useCallback(async()=>{const d=await sGetShared("leaderboard")||[];setLb(d.sort((a,b)=>b.score-a.score).slice(0,20));},[]);
  useEffect(()=>{if(screen==="leaderboard")loadLb();},[screen]);

  const startLesson=(chId,reviewMode)=>{const ch=CH.find(c=>c.id===(chId||chapter));const wEx=genEx(ch.words,lang,reviewMode?weakWords:null);const sEx=reviewMode?[]:genSentenceEx(ch.sentences);setExercises([...wEx,...sEx]);setCur(0);setScore(0);setStreak(0);setHearts(5);setXp(0);setFb(null);setSel(null);setTyped("");setHUsed(false);setDk(k=>k+1);setIsReview(!!reviewMode);setIsExam(false);setExamOver(false);setShowGrammar(false);setChapter(chId||chapter);setScreen("exercise");const started=new Set(Object.keys(progress.chS||{}));started.add(String(chId||chapter));saveP({cs:started.size});};

  const startExam=(chIds)=>{const allWords=chIds.flatMap(id=>{const ch=CH.find(c=>c.id===id);return ch?ch.words:[];});const ex=genEx(allWords,lang,null,true,true);const sentEx=chIds.flatMap(id=>{const ch=CH.find(c=>c.id===id);return genSentenceEx(ch?.sentences);});setExercises(shuffle([...ex,...sentEx]).slice(0,25));setCur(0);setScore(0);setStreak(0);setHearts(5);setXp(0);setFb(null);setSel(null);setTyped("");setHUsed(false);setDk(k=>k+1);setIsReview(false);setIsExam(true);setExamOver(false);setShowGrammar(false);setScreen("exercise");};

  const startReview=()=>{if(weakWords.length<4)return;const allW=CH.flatMap(c=>c.words);const rw=allW.filter(w=>new Set(weakWords).has(w.d));if(rw.length<4)return;setExercises(genEx(rw,lang,weakWords));setCur(0);setScore(0);setStreak(0);setHearts(5);setXp(0);setFb(null);setSel(null);setTyped("");setHUsed(false);setDk(k=>k+1);setIsReview(true);setIsExam(false);setScreen("exercise");};

  useEffect(()=>{if(screen==="exercise"&&exercises[cur]&&["tw","fb"].includes(exercises[cur].type))setTimeout(()=>{if(iRef.current)iRef.current.focus();},100);},[cur,screen]);
  // Auto-play listening exercise
  useEffect(()=>{if(screen==="exercise"&&exercises[cur]&&exercises[cur].type==="listen")setTimeout(()=>speakNL(exercises[cur].word),300);},[cur,screen]);

  const checkAnswer=()=>{const ex=exercises[cur];let ok=false;if(ex.type==="mc"||ex.type==="listen"||ex.type==="emoji")ok=sel===ex.ca;else if(ex.type==="tw")ok=typed.trim().toLowerCase()===ex.ca.toLowerCase();else if(ex.type==="fb")ok=typed.trim().toLowerCase()===ex.answer.toLowerCase();const pen=hUsed?5:0;if(ok){const b=streak>=3?5:streak>=2?3:0;const pts=Math.max(0,10+b-pen);setScore(s=>s+pts);setStreak(s=>s+1);setXp(x=>x+pts);if(streak>=2)sStreak();else sCorrect();setTimeout(()=>{const w=ex.dw||ex.ca||ex.word||ex.answer;if(w)speakNL(w);},500);}else{setStreak(0);setHearts(h=>Math.max(0,h-1));setShk(true);setTimeout(()=>setShk(false),500);sWrong();setTimeout(()=>{const w=ex.dw||ex.ca||ex.word||ex.answer;if(w)speakNL(w);},600);const word=ex.dw||ex.ca||ex.answer||ex.word;if(word&&!weakWords.includes(word)){const nw=[...weakWords,word];saveP({ww:nw});}}setFb({ok,ca:ex.ca||ex.answer});};

  const onDragDone=(ok,cc,tc)=>{const pts=cc*10;setScore(s=>s+pts);setXp(x=>x+pts);if(ok){setStreak(s=>s+1);sCorrect();}else{setStreak(0);setHearts(h=>Math.max(0,h-(tc-cc)));setShk(true);setTimeout(()=>setShk(false),500);sWrong();}setFb({ok,ca:cc+"/"+tc});};

  const nextEx=()=>{if(cur+1>=total||hearts<=0||examOver){setScreen("complete");if(score>total*3)setConf(true);sDone();const mx=total*10;const pct=Math.min(100,Math.round(score/mx*100));const cs={...(progress.chS||{})};if(chapter)cs[chapter]=Math.max(cs[chapter]||0,pct);const cw=exercises.filter((_,i)=>i<=cur).map(e=>e.dw||e.ca||e.answer||e.word).filter(Boolean);const uw=(weakWords||[]).filter(w=>!cw.includes(w));const learned=new Set(Object.keys(cs).flatMap(id=>{const ch=CH.find(c=>c.id===Number(id));return ch?ch.words.map(w=>w.d):[];}));saveP({lc:(progress.lc||0)+1,ps:(progress.ps||0)+(pct>=100?1:0),rd:(progress.rd||0)+(isReview?1:0),ex:(progress.ex||0)+(isExam?1:0),lu:Math.max(progress.lu||0,new Set([lang,...(progress.ul||[])]).size),ul:[...new Set([lang,...(progress.ul||[])])],chS:cs,wl:learned.size,ww:uw});}else{setCur(c=>c+1);setSel(null);setTyped("");setFb(null);setHUsed(false);setDk(k=>k+1);}};

  const cS={minHeight:"100vh",minHeight:"100dvh",background:"linear-gradient(180deg,var(--c-bg),var(--c-bg2),var(--c-bg3))",fontFamily:"'Nunito','Segoe UI',sans-serif",direction:isRTL?"rtl":"ltr",paddingTop:"env(safe-area-inset-top)",paddingBottom:"env(safe-area-inset-bottom)"};
  const card={background:"var(--c-card)",borderRadius:18,padding:"22px 18px",maxWidth:520,width:"94%",margin:"0 auto",boxShadow:"0 4px 20px rgba(0,0,0,.06)",border:"2px solid var(--c-border)"};
  const gBtn=(a)=>({width:"100%",padding:"16px",border:"none",borderRadius:14,fontSize:16,fontWeight:800,cursor:a?"pointer":"default",textTransform:"uppercase",letterSpacing:1,fontFamily:"'Nunito'",background:a?"linear-gradient(135deg,#58CC02,#46A302)":"var(--c-muted-bg)",color:a?"white":"var(--c-sub)",boxShadow:a?"0 4px 10px rgba(88,204,2,.3),0 3px 0 #3C8C00":"none",minHeight:52,touchAction:"manipulation"});
  const topBar=(<div style={{display:"flex",justifyContent:"flex-end",gap:8,padding:"10px 16px",maxWidth:560,margin:"0 auto"}}><button onClick={()=>setDark(!dark)} style={{background:"none",border:"none",cursor:"pointer",fontSize:18,padding:8,minWidth:40,minHeight:40}}>{dark?"☀️":"🌙"}</button><button onClick={()=>{setSnd(!snd);soundOn=!snd;}} style={{background:"none",border:"none",cursor:"pointer",fontSize:18,padding:8,minWidth:40,minHeight:40}}>{snd?"🔊":"🔇"}</button></div>);

  // ─── LANG SELECT ───
  if(screen==="lang")return(<div style={cS}><style>{CSS}</style>{topBar}<div style={{display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",minHeight:"80vh",padding:24}}><div style={{animation:"float 3s ease-in-out infinite",marginBottom:14}}><MiniCat v={0} w={90} h={90}/></div><h1 style={{fontSize:30,fontWeight:900,color:"var(--c-text)"}}>Leer Nederlands</h1><p style={{fontSize:13,color:"var(--c-sub)",marginBottom:24,fontWeight:600}}>Learn Dutch · هلندی یاد بگیرید</p><div style={{...card,animation:"fadeUp .5s ease-out"}}><p style={{fontSize:15,fontWeight:700,color:"var(--c-text)",textAlign:"center",marginBottom:16}}>🐱 Choose your language</p>{LANGS.map((l,i)=>(<button key={l.c} onClick={()=>{setLang(l.c);setScreen("chapters");saveP({lu:Math.max(progress.lu||0,1),ul:[...new Set([l.c,...(progress.ul||[])])]});}} style={{display:"flex",alignItems:"center",gap:12,width:"100%",padding:"14px 18px",background:["#1CB0F6","#A855F7"][i],border:"none",borderRadius:12,cursor:"pointer",marginBottom:i<3?8:0,color:"white",fontSize:15,fontWeight:800}}><span style={{fontSize:22}}>{l.f}</span>{l.n}</button>))}</div>{dailyStreak>0&&<div style={{marginTop:14,padding:"8px 16px",background:"var(--c-card)",borderRadius:10,border:"2px solid var(--c-border)",textAlign:"center"}}><span style={{fontSize:20}}>🔥</span><span style={{fontSize:13,fontWeight:800,color:"var(--c-text)",marginLeft:6}}>{dailyStreak} {UI.en.days}!</span></div>}</div></div>);

  // ─── CHAPTERS ───
  if(screen==="chapters")return(<div style={cS}><style>{CSS}</style>{topBar}<div style={{maxWidth:560,margin:"0 auto",padding:"0 20px 24px"}}><div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:14}}><button onClick={()=>{setScreen("lang");setLang(null);}} style={{background:"none",border:"none",cursor:"pointer",fontSize:12,fontWeight:700,color:"var(--c-sub)"}}>{"← "+ui.back}</button><div style={{display:"flex",gap:4}}><button onClick={()=>setScreen("achievements")} style={{background:"none",border:"none",cursor:"pointer",fontSize:20,padding:8,minWidth:40,minHeight:40}}>🏆</button><button onClick={()=>setScreen("leaderboard")} style={{background:"none",border:"none",cursor:"pointer",fontSize:20,padding:8,minWidth:40,minHeight:40}}>📊</button><button onClick={()=>setScreen("exam_setup")} style={{background:"none",border:"none",cursor:"pointer",fontSize:20,padding:8,minWidth:40,minHeight:40}}>📝</button></div></div><h2 style={{fontSize:22,fontWeight:900,color:"var(--c-text)",textAlign:"center",marginBottom:2}}>Start.nl</h2>{dailyStreak>0&&<p style={{textAlign:"center",fontSize:12,fontWeight:700,color:"#FF6B35",marginBottom:2}}>🔥 {dailyStreak} {ui.days} {ui.dailyStreak}</p>}<p style={{fontSize:12,color:"var(--c-sub)",textAlign:"center",fontWeight:600,marginBottom:16}}>{ui.selectCh}</p><div style={{display:"flex",flexDirection:"column",gap:8}}>{CH.map((ch,i)=>{const pct=progress.chS?.[ch.id]||0;return(<button key={ch.id} onClick={()=>{setChapter(ch.id);setScreen("intro");}} style={{display:"flex",alignItems:"center",gap:12,padding:"14px 14px",minHeight:56,background:"var(--c-card)",border:"2px solid var(--c-border)",borderRadius:14,cursor:"pointer",animation:"fadeUp .3s ease-out "+(i*.03)+"s both",transition:"all .15s"}}><div style={{width:38,height:38,borderRadius:10,background:chColors[i],display:"flex",alignItems:"center",justifyContent:"center",fontSize:15,fontWeight:900,color:"white",flexShrink:0}}>{ch.id}</div><div style={{flex:1,textAlign:isRTL?"right":"left"}}><div style={{fontSize:13,fontWeight:800,color:"var(--c-text)"}}>{lang==="fa"?ch.fa:ch.en}</div><div style={{fontSize:10,fontWeight:600,color:"var(--c-sub)"}}>{ch.words.length+" "+ui.wordCount}{pct>0&&(" · "+pct+"%")}</div></div>{pct>=90&&<span>⭐</span>}<span style={{color:"var(--c-border)",fontSize:14}}>→</span></button>);})}</div>{weakWords.length>=4&&<button onClick={startReview} style={{...gBtn(true),marginTop:14,background:"linear-gradient(135deg,#FF6B35,#E65100)"}}>{"🔄 "+ui.review+" ("+weakWords.length+")"}</button>}</div></div>);

  // ─── ACHIEVEMENTS ───
  if(screen==="achievements")return(<div style={cS}><style>{CSS}</style>{topBar}<div style={{maxWidth:560,margin:"0 auto",padding:"0 20px 24px"}}><button onClick={()=>setScreen("chapters")} style={{background:"none",border:"none",cursor:"pointer",fontSize:12,fontWeight:700,color:"var(--c-sub)",marginBottom:14}}>{"← "+ui.back}</button><h2 style={{fontSize:22,fontWeight:900,color:"var(--c-text)",textAlign:"center",marginBottom:16}}>{"🏆 "+ui.achievements}</h2><div style={{display:"flex",flexDirection:"column",gap:8}}>{BADGES.map(b=>{const u=badges.includes(b.id);return(<div key={b.id} style={{...card,padding:"14px",display:"flex",alignItems:"center",gap:12,opacity:u?1:.4}}><div style={{fontSize:28,filter:u?"none":"grayscale(1)"}}>{b.icon}</div><div style={{flex:1}}><div style={{fontSize:14,fontWeight:800,color:"var(--c-text)"}}>{b.name}</div></div>{u&&<span>✅</span>}</div>);})}</div><p style={{textAlign:"center",marginTop:14,fontSize:12,color:"var(--c-sub)"}}>{badges.length+"/"+BADGES.length}</p></div></div>);

  // ─── LEADERBOARD ───
  if(screen==="leaderboard")return(<div style={cS}><style>{CSS}</style>{topBar}<div style={{maxWidth:560,margin:"0 auto",padding:"0 20px 24px"}}><button onClick={()=>setScreen("chapters")} style={{background:"none",border:"none",cursor:"pointer",fontSize:12,fontWeight:700,color:"var(--c-sub)",marginBottom:14}}>{"← "+ui.back}</button><h2 style={{fontSize:22,fontWeight:900,color:"var(--c-text)",textAlign:"center",marginBottom:16}}>{"📊 "+ui.leaderboard}</h2>{lb.length===0?<p style={{textAlign:"center",color:"var(--c-sub)",fontSize:14}}>{ui.lbEmpty}</p>:<div style={{display:"flex",flexDirection:"column",gap:6}}>{lb.map((e,i)=>(<div key={i} style={{...card,padding:"12px 16px",display:"flex",alignItems:"center",gap:10}}><div style={{width:32,height:32,borderRadius:"50%",background:i===0?"#FFD600":i===1?"#B0BEC5":i===2?"#FFAB91":"var(--c-muted-bg)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:14,fontWeight:900,color:i<3?"white":"var(--c-text)"}}>{i+1}</div><div style={{flex:1}}><div style={{fontSize:14,fontWeight:800,color:"var(--c-text)"}}>{e.name}</div><div style={{fontSize:11,color:"var(--c-sub)"}}>{"H"+(e.ch||"?")+" · "+e.lang}</div></div><div style={{fontSize:16,fontWeight:900,color:"#FFB300"}}>{e.score}</div></div>))}</div>}<div style={{marginTop:16,...card,padding:"14px"}}><p style={{fontSize:13,fontWeight:700,color:"var(--c-text)",marginBottom:8}}>{ui.lbName}</p><input value={lbName} onChange={e=>setLbName(e.target.value)} placeholder="..." style={{width:"100%",padding:"10px",borderRadius:10,border:"2px solid var(--c-border)",fontSize:14,fontWeight:700,background:"var(--c-muted-bg)",color:"var(--c-text)",marginBottom:8,outline:"none"}}/><button onClick={async()=>{if(!lbName.trim())return;const entry={name:lbName.trim(),score:progress.wl||0,lang:lang,ch:Object.keys(progress.chS||{}).length,date:new Date().toISOString().slice(0,10)};const cur=await sGetShared("leaderboard")||[];cur.push(entry);await sSetShared("leaderboard",cur.sort((a,b)=>b.score-a.score).slice(0,50));loadLb();}} style={gBtn(!!lbName.trim())}>{ui.lbSubmit}</button></div></div></div>);

  // ─── EXAM SETUP ───
  if(screen==="exam_setup")return(<div style={cS}><style>{CSS}</style>{topBar}<div style={{maxWidth:560,margin:"0 auto",padding:"0 20px 24px"}}><button onClick={()=>setScreen("chapters")} style={{background:"none",border:"none",cursor:"pointer",fontSize:12,fontWeight:700,color:"var(--c-sub)",marginBottom:14}}>{"← "+ui.back}</button><h2 style={{fontSize:22,fontWeight:900,color:"var(--c-text)",textAlign:"center",marginBottom:4}}>{"📝 "+ui.exam}</h2><p style={{fontSize:13,color:"var(--c-sub)",textAlign:"center",marginBottom:16}}>{ui.examDesc}</p><div style={{display:"flex",flexDirection:"column",gap:6}}>{CH.map((ch,i)=>{const sel2=examChapters.includes(ch.id);return(<button key={ch.id} onClick={()=>setExamChapters(ec=>sel2?ec.filter(x=>x!==ch.id):[...ec,ch.id])} style={{display:"flex",alignItems:"center",gap:10,padding:"10px 14px",background:sel2?"#E3F2FD":"var(--c-card)",border:"2px solid "+(sel2?"#1CB0F6":"var(--c-border)"),borderRadius:12,cursor:"pointer"}}><div style={{width:24,height:24,borderRadius:6,background:sel2?"#1CB0F6":"var(--c-muted-bg)",display:"flex",alignItems:"center",justifyContent:"center",color:"white",fontSize:14,fontWeight:900}}>{sel2?"✓":""}</div><span style={{fontSize:13,fontWeight:700,color:"var(--c-text)"}}>{ch.id+". "+(lang==="fa"?ch.fa:ch.en)}</span></button>);})}</div>{examChapters.length>=2&&<button onClick={()=>startExam(examChapters)} style={{...gBtn(true),marginTop:14,background:"linear-gradient(135deg,#1CB0F6,#0095E8)"}}>{ui.examStart+" (5 "+ui.examTime+")"}</button>}{examChapters.length<2&&<p style={{textAlign:"center",marginTop:12,fontSize:12,color:"var(--c-sub)"}}>Select at least 2 chapters</p>}</div></div>);

  // ─── INTRO ───
  if(screen==="intro"){const ch=CH.find(c=>c.id===chapter);const preview=ch.words.slice(0,6);const gt=GRAMMAR[chapter];return(<div style={cS}><style>{CSS}</style>{topBar}<div style={{display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",minHeight:"80vh",padding:24}}><div style={{...card,animation:"fadeUp .5s ease-out",textAlign:"center"}}><button onClick={()=>setScreen("chapters")} style={{background:"none",border:"none",cursor:"pointer",fontSize:12,fontWeight:700,color:"var(--c-sub)",marginBottom:10}}>{"← "+ui.back}</button><div style={{display:"inline-flex",background:"#FFF3E0",borderRadius:12,padding:"5px 14px",marginBottom:10}}><span style={{fontSize:12,fontWeight:800,color:"#FF6B35"}}>{"🐾 H"+chapter+" — "+(lang==="fa"?ch.fa:ch.en)}</span></div><p style={{color:"var(--c-sub)",fontSize:12,fontWeight:600,marginBottom:12}}>{ch.words.length+" "+ui.wordCount}</p>{gt&&!showGrammar&&<button onClick={()=>setShowGrammar(true)} style={{background:"linear-gradient(135deg,#E3F2FD,#BBDEFB)",border:"2px solid #90CAF9",borderRadius:10,padding:"8px 16px",cursor:"pointer",fontSize:12,fontWeight:700,color:"#1565C0",marginBottom:12,width:"100%"}}>{"📖 "+ui.grammarShow}</button>}{showGrammar&&gt&&<div style={{background:"linear-gradient(135deg,#E3F2FD,#BBDEFB)",border:"2px solid #90CAF9",borderRadius:12,padding:"12px 16px",marginBottom:12,textAlign:isRTL?"right":"left",animation:"bounceIn .3s ease-out"}}><p style={{fontSize:11,fontWeight:800,color:"#1565C0",marginBottom:4}}>{"📖 "+ui.grammar}</p><p style={{fontSize:13,fontWeight:600,color:"#0D47A1",lineHeight:1.5}}>{gt[lang]||gt.en}</p></div>}{preview.map((w,i)=>(<div key={i} style={{display:"flex",alignItems:"center",justifyContent:"space-between",background:"var(--c-muted-bg)",borderRadius:10,padding:"8px 12px",marginBottom:4,border:"2px solid var(--c-border)"}}><div style={{display:"flex",alignItems:"center",gap:4}}><span style={{fontWeight:800,fontSize:13,color:"var(--c-text)"}}>{w.d}</span><SpeakerBtn word={w.d}/>{EMOJI[w.d]&&<span style={{fontSize:14}}>{EMOJI[w.d]}</span>}</div><span style={{color:"var(--c-sub)",fontSize:12,fontWeight:600}}>{w[lang]||w.en}</span></div>))}{ch.words.length>6&&<p style={{fontSize:11,color:"var(--c-sub)",marginTop:2}}>{"+"+(ch.words.length-6)+" more..."}</p>}<button onClick={()=>startLesson(chapter)} style={{...gBtn(true),marginTop:12,animation:"pulse 2s ease-in-out infinite"}}>{ui.startLesson+" →"}</button><button onClick={()=>{setChapter(chapter);setScreen("flashcards");}} style={{width:"100%",padding:"14px",background:"linear-gradient(135deg,#FFB347,#FF9800)",border:"none",borderRadius:14,color:"white",fontSize:15,fontWeight:800,cursor:"pointer",marginTop:8,minHeight:48,fontFamily:"'Nunito'",boxShadow:"0 4px 10px rgba(255,179,71,.3),0 3px 0 #F57C00"}}>{"🃏 "+(ui.flashcards||"Flashcards")}</button></div></div></div>);}

  // ─── FLASHCARDS ───
  if(screen==="flashcards"){const ch=CH.find(c=>c.id===chapter);return(<div style={cS}><style>{CSS}</style>{topBar}<div style={{maxWidth:520,width:"94%",margin:"0 auto",padding:"0 0 24px"}}><FlashcardGame words={ch.words} lang={lang} ui={ui} onBack={()=>setScreen("intro")}/></div></div>);}

  // ─── EXERCISE ───
  if(screen==="exercise"){const ex=exercises[cur];if(!ex)return null;return(<div style={cS}><style>{CSS}</style><div style={{maxWidth:540,margin:"0 auto",padding:"12px 14px 0",minHeight:"100dvh",display:"flex",flexDirection:"column"}}><div style={{display:"flex",alignItems:"center",gap:10,marginBottom:12}}><button onClick={()=>setScreen("chapters")} style={{background:"none",border:"none",cursor:"pointer",fontSize:20,color:"var(--c-sub)",padding:8,minWidth:40,minHeight:40}}>✕</button><div style={{flex:1}}><ProgressBar current={cur} total={total}/></div><div style={{display:"flex",gap:2,flexShrink:0}}>{Array.from({length:5}).map((_,i)=><PawIcon key={i} filled={i<hearts}/>)}</div></div>{isExam&&<Timer seconds={300} onDone={()=>setExamOver(true)}/>}<div style={{display:"flex",justifyContent:"space-between",marginBottom:12,background:"var(--c-card)",borderRadius:10,padding:"6px 14px",border:"2px solid var(--c-border)"}}><div><div style={{fontSize:9,fontWeight:700,color:"var(--c-sub)"}}>{ui.score}</div><div style={{fontSize:16,fontWeight:900,color:"#FFB300"}}>{score}</div></div><div><div style={{fontSize:9,fontWeight:700,color:"var(--c-sub)"}}>{ui.streak}</div><div style={{fontSize:16,fontWeight:900,color:streak>=3?"#FF6B35":"var(--c-text)"}}>{streak}</div></div></div><div style={{...card,width:"100%",maxWidth:"100%",flex:1,animation:shk?"shake .5s":"slideUp .4s ease-out"}}>
        {/* MC */}
        {ex.type==="mc"&&(<><p style={{fontSize:13,fontWeight:700,color:"var(--c-sub)",marginBottom:5,textAlign:"center"}}>{ui.choose}</p><div style={{textAlign:"center",marginBottom:6}}><span style={{display:"inline-block",background:"linear-gradient(135deg,#EEF7FF,#E0F0FF)",borderRadius:12,padding:"12px 24px",fontSize:22,fontWeight:900,color:"#1CB0F6",border:"2px solid #C4E3FF"}}>{ex.dw}<SpeakerBtn word={ex.dw}/></span></div><div style={{display:"flex",flexDirection:"column",gap:6,marginTop:10}}>{ex.opts.map((o,i)=>{let bg="var(--c-card)",bc="var(--c-border)",c="var(--c-text)";if(fb){if(o===ex.ca){bg="#E8F9E0";bc="#58CC02";c="#2E7D00";}else if(o===sel&&!fb.ok){bg="#FFE8E8";bc="#FF4B4B";c="#C00";}}else if(o===sel){bg="#E0F0FF";bc="#1CB0F6";c="#0077CC";}return(<button key={i} onClick={()=>{if(!fb){setSel(o);sClick();}}} disabled={!!fb} style={{width:"100%",padding:"14px 16px",minHeight:48,background:bg,border:"2px solid "+bc,borderRadius:10,fontSize:14,fontWeight:700,color:c,cursor:fb?"default":"pointer",fontFamily:"'Nunito'",textAlign:isRTL?"right":"left"}}>{o}</button>)})}</div>{!fb&&<HintBtn hint={ex.hint} label={ui.hint} onUse={()=>{setHUsed(true);setXp(x=>Math.max(0,x-5));}}/>}</>)}
        {/* LISTEN */}
        {ex.type==="listen"&&(<><p style={{fontSize:13,fontWeight:700,color:"var(--c-sub)",marginBottom:5,textAlign:"center"}}>{ui.listen}</p><div style={{textAlign:"center",marginBottom:10}}><button onClick={()=>speakNL(ex.word)} style={{background:"linear-gradient(135deg,#E3F2FD,#BBDEFB)",border:"2px solid #90CAF9",borderRadius:16,padding:"20px 40px",cursor:"pointer",fontSize:40}}>🔊</button><p style={{fontSize:11,color:"var(--c-sub)",marginTop:4}}>Click to listen again</p></div><div style={{display:"flex",flexDirection:"column",gap:6}}>{ex.opts.map((o,i)=>{let bg="var(--c-card)",bc="var(--c-border)",c="var(--c-text)";if(fb){if(o===ex.ca){bg="#E8F9E0";bc="#58CC02";c="#2E7D00";}else if(o===sel&&!fb.ok){bg="#FFE8E8";bc="#FF4B4B";c="#C00";}}else if(o===sel){bg="#E0F0FF";bc="#1CB0F6";c="#0077CC";}return(<button key={i} onClick={()=>{if(!fb){setSel(o);sClick();}}} disabled={!!fb} style={{width:"100%",padding:"14px 16px",minHeight:48,background:bg,border:"2px solid "+bc,borderRadius:10,fontSize:14,fontWeight:700,color:c,cursor:fb?"default":"pointer",fontFamily:"'Nunito'"}}>{o}<SpeakerBtn word={o}/></button>)})}</div>{!fb&&<HintBtn hint={ex.hint} label={ui.hint} onUse={()=>{setHUsed(true);setXp(x=>Math.max(0,x-5));}}/>}</>)}
        {/* EMOJI */}
        {ex.type==="emoji"&&(<><p style={{fontSize:13,fontWeight:700,color:"var(--c-sub)",marginBottom:5,textAlign:"center"}}>{ui.emojiQ}</p><div style={{textAlign:"center",marginBottom:10}}><span style={{fontSize:64}}>{ex.emoji}</span></div><div style={{display:"flex",flexDirection:"column",gap:6}}>{ex.opts.map((o,i)=>{let bg="var(--c-card)",bc="var(--c-border)",c="var(--c-text)";if(fb){if(o===ex.ca){bg="#E8F9E0";bc="#58CC02";c="#2E7D00";}else if(o===sel&&!fb.ok){bg="#FFE8E8";bc="#FF4B4B";c="#C00";}}else if(o===sel){bg="#E0F0FF";bc="#1CB0F6";c="#0077CC";}return(<button key={i} onClick={()=>{if(!fb){setSel(o);sClick();}}} disabled={!!fb} style={{width:"100%",padding:"14px 16px",minHeight:48,background:bg,border:"2px solid "+bc,borderRadius:10,fontSize:14,fontWeight:700,color:c,cursor:fb?"default":"pointer",fontFamily:"'Nunito'"}}>{o}{EMOJI[o]?" "+EMOJI[o]:""}<SpeakerBtn word={o}/></button>)})}</div>{!fb&&<HintBtn hint={ex.hint} label={ui.hint} onUse={()=>{setHUsed(true);setXp(x=>Math.max(0,x-5));}}/>}</>)}
        {/* TYPE */}
        {ex.type==="tw"&&(<><p style={{fontSize:13,fontWeight:700,color:"var(--c-sub)",marginBottom:5,textAlign:"center"}}>{ui.type}</p><div style={{textAlign:"center",marginBottom:12}}><span style={{fontSize:18}}>{'"'+ex.tr+'"'}</span><span style={{color:"var(--c-sub)",fontSize:13}}>{" "+ui.meaning+":"}</span></div><input ref={iRef} type="text" value={typed} onChange={e=>setTyped(e.target.value)} onKeyDown={e=>{if(e.key==="Enter"&&!fb&&typed)checkAnswer();}} disabled={!!fb} placeholder="..." autoComplete="off" style={{width:"100%",padding:"14px 12px",fontSize:18,fontWeight:700,border:"3px solid "+(fb?(fb.ok?"#58CC02":"#FF4B4B"):"var(--c-border)"),borderRadius:10,textAlign:"center",outline:"none",background:fb?(fb.ok?"#F0FFF0":"#FFF5F5"):"var(--c-muted-bg)",color:"var(--c-text)",fontFamily:"'Nunito'"}}/>{fb&&!fb.ok&&<p style={{textAlign:"center",marginTop:8,fontSize:13,color:"#FF4B4B",fontWeight:700}}>{ui.tryAgain+": "}<strong style={{color:"var(--c-text)"}}>{fb.ca}</strong><SpeakerBtn word={fb.ca}/></p>}{fb&&fb.ok&&<div style={{textAlign:"center",marginTop:4}}><SpeakerBtn word={fb.ca}/></div>}{!fb&&<HintBtn hint={ex.hint} label={ui.hint} onUse={()=>{setHUsed(true);setXp(x=>Math.max(0,x-5));}}/>}</>)}
        {/* FILL BLANK */}
        {ex.type==="fb"&&(<><p style={{fontSize:13,fontWeight:700,color:"var(--c-sub)",marginBottom:5,textAlign:"center"}}>{ui.fill}</p><div style={{textAlign:"center",marginBottom:12,fontSize:17,fontWeight:700,color:"var(--c-text)",lineHeight:1.8}}>{ex.sentence.replace(/_+/," _____ ")}<SpeakerBtn word={ex.sentence.replace(/_+/,ex.answer)}/></div><input ref={iRef} type="text" value={typed} onChange={e=>setTyped(e.target.value)} onKeyDown={e=>{if(e.key==="Enter"&&!fb&&typed)checkAnswer();}} disabled={!!fb} placeholder="..." autoComplete="off" style={{width:"100%",padding:"14px 12px",fontSize:18,fontWeight:700,border:"3px solid "+(fb?(fb.ok?"#58CC02":"#FF4B4B"):"var(--c-border)"),borderRadius:10,textAlign:"center",outline:"none",background:fb?(fb.ok?"#F0FFF0":"#FFF5F5"):"var(--c-muted-bg)",color:"var(--c-text)",fontFamily:"'Nunito'"}}/>{fb&&!fb.ok&&<p style={{textAlign:"center",marginTop:8,fontSize:13,color:"#FF4B4B",fontWeight:700}}>{ui.tryAgain+": "}<strong style={{color:"var(--c-text)"}}>{fb.ca}</strong><SpeakerBtn word={fb.ca}/></p>}{fb&&fb.ok&&<div style={{textAlign:"center",marginTop:6}}><SpeakerBtn word={ex.sentence.replace(/_+/,ex.answer)} big/><p style={{fontSize:11,color:"var(--c-sub)"}}>{"🔊 "+ex.sentence.replace(/_+/,ex.answer)}</p></div>}{!fb&&ex.hint&&<HintBtn hint={ex.hint} label={ui.hint} onUse={()=>{setHUsed(true);setXp(x=>Math.max(0,x-5));}}/>}</>)}
        {/* DRAG */}
        {ex.type==="dm"&&!fb&&<DragMatch key={dk} pairs={ex.pairs} isRTL={isRTL} ui={ui} onDone={onDragDone}/>}
        {ex.type==="dm"&&fb&&<div style={{textAlign:"center",padding:"12px 0"}}><p style={{fontSize:16,fontWeight:900,color:fb.ok?"#2E7D00":"#C00"}}>{fb.ok?("😻 "+ui.correct):("🙀 "+fb.ca+" correct")}</p></div>}
      </div>
      {fb&&<div style={{marginTop:10,padding:"12px 14px",borderRadius:12,background:fb.ok?"linear-gradient(135deg,#E8F9E0,#D4F4C4)":"linear-gradient(135deg,#FFE8E8,#FFD4D4)",border:"2px solid "+(fb.ok?"#58CC02":"#FF4B4B"),textAlign:"center",animation:"bounceIn .3s ease-out"}}><CatReward ok={fb.ok}/>{ex.type!=="dm"&&<p style={{fontSize:14,fontWeight:900,color:fb.ok?"#2E7D00":"#C00"}}>{fb.ok?("😻 "+ui.correct):("🙀 "+ui.incorrect)}</p>}<div style={{marginTop:6}}><button onClick={()=>speakNL(ex.dw||ex.ca||ex.word||ex.answer||"")} style={{background:"linear-gradient(135deg,#E3F2FD,#BBDEFB)",border:"2px solid #90CAF9",borderRadius:10,padding:"8px 20px",cursor:"pointer",fontSize:14,fontWeight:700,color:"#1565C0"}}>🔊 {ex.dw||ex.ca||ex.word||ex.answer||""}</button></div></div>}
      <div style={{marginTop:12,paddingBottom:"max(16px, env(safe-area-inset-bottom))",position:"sticky",bottom:0,background:"linear-gradient(transparent, var(--c-bg2) 20%)",paddingTop:12}}>{!fb&&ex.type!=="dm"?<button onClick={checkAnswer} disabled={["mc","listen","emoji"].includes(ex.type)?!sel:!typed.trim()} style={gBtn(["mc","listen","emoji"].includes(ex.type)?!!sel:!!typed.trim())}>{ui.check}</button>:fb?<button onClick={nextEx} style={gBtn(true)}>{ui.next+" →"}</button>:null}</div>
    </div></div>);}

  // ─── COMPLETE ───
  if(screen==="complete"){const mx=total*10;const pct=Math.min(100,Math.round(score/mx*100));const msg=pct>=90?ui.perfect:pct>=50?ui.greatJob:ui.keepGoing;return(<div style={cS}><style>{CSS}</style>{conf&&<div style={{position:"fixed",inset:0,pointerEvents:"none",zIndex:999}}><style>{"@keyframes cF{0%{transform:translateY(-20px) rotate(0);opacity:1}100%{transform:translateY(100vh) rotate(720deg);opacity:0}}"}</style>{Array.from({length:40},(_,i)=><div key={i} style={{position:"absolute",left:(Math.random()*100)+"%",top:-20,width:6+Math.random()*8,height:6+Math.random()*8,background:["#FFB347","#FF6B9D","#FFD600","#CE82FF","#1CB0F6"][i%5],borderRadius:Math.random()>.5?"50%":"2px",animation:"cF "+(1.5+Math.random()*1.5)+"s ease-in "+(Math.random()*.5)+"s forwards"}}/>)}</div>}<div style={{display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",minHeight:"100vh",padding:24}}><div style={{...card,textAlign:"center",animation:"bounceIn .6s ease-out"}}><MiniCat v={(chapter||0)%12} w={70} h={70}/><CatReward ok={pct>=50} big/><h2 style={{fontSize:22,fontWeight:900,color:"var(--c-text)",marginBottom:3}}>{isExam?ui.examDone:ui.complete}</h2><p style={{fontSize:13,color:"var(--c-sub)",fontWeight:600,marginBottom:14}}>{msg}</p>{dailyStreak>0&&<p style={{fontSize:12,fontWeight:700,color:"#FF6B35",marginBottom:8}}>{"🔥 "+dailyStreak+" "+ui.days+"!"}</p>}<div style={{display:"flex",justifyContent:"center",gap:12,marginBottom:18}}>{[{v:xp,l:ui.xp,bg:"#FFD600"},{v:pct+"%",l:ui.score,bg:"#58CC02"},{v:hearts,l:ui.hearts,bg:"#FF6B9D"}].map((it,i)=>(<div key={i} style={{textAlign:"center"}}><div style={{width:50,height:50,borderRadius:"50%",background:it.bg,display:"flex",alignItems:"center",justifyContent:"center",margin:"0 auto 4px"}}><span style={{fontSize:16,fontWeight:900,color:"white"}}>{it.v}</span></div><span style={{fontSize:10,fontWeight:700,color:"var(--c-sub)"}}>{it.l}</span></div>))}</div>{!isExam&&chapter&&<button onClick={()=>{setConf(false);startLesson(chapter);}} style={{width:"100%",padding:"12px",background:"#1CB0F6",border:"none",borderRadius:12,color:"white",fontSize:14,fontWeight:800,cursor:"pointer",marginBottom:8}}>{"🐱 "+ui.restart}</button>}<button onClick={()=>{setScreen("chapters");setConf(false);}} style={{width:"100%",padding:"10px",background:"transparent",border:"2px solid var(--c-border)",borderRadius:12,color:"var(--c-sub)",fontSize:13,fontWeight:700,cursor:"pointer"}}>{"🐾 "+ui.selectCh}</button></div></div></div>);}
  return null;
}
